/**
 * ProviderGlyphs — small monochrome icons for LLM providers and local model
 * families, shown in the Model Settings dropdown and the built-in model cards.
 *
 * All glyphs use `currentColor` so they inherit the surrounding ink/muted text
 * color and adapt to light/dark. Per the Signal Rule they are never amber —
 * icons are wayfinding, not the one signal that matters.
 *
 * Brand marks use the official logo geometry (Anthropic, OpenAI, Ollama,
 * Qwen, OpenRouter, and the Google spark for Gemma), rendered as a single
 * monochrome `currentColor` fill so they stay on-brand with Signal Desk.
 * Providers without a clean official mark (Groq, custom endpoints) keep a
 * semantic Heroicon.
 */

import {
  CpuChipIcon,
  CommandLineIcon,
  BoltIcon,
  ServerIcon,
  SparklesIcon,
} from '@heroicons/react/24/outline';
import { cn } from '@/lib/utils';

const GLYPH = 'h-4 w-4 shrink-0';

type GlyphProps = { className?: string };

