/** Icon for a summarization provider, keyed by the provider id. */
export function ProviderGlyph({
  provider,
  className,
}: {
  provider: string;
  className?: string;
}) {
  switch (provider) {
    case 'builtin-ai':
      return <CpuChipIcon className={cn(GLYPH, className)} aria-hidden="true" />;
    case 'claude':
      return <AnthropicGlyph className={className} />;
    case 'claude-cli':
      return <CommandLineIcon className={cn(GLYPH, className)} aria-hidden="true" />;
    case 'apple-foundation':
      return <AppleGlyph className={className} />;
    case 'openai':
      return <OpenAIGlyph className={className} />;
    case 'groq':
      return <BoltIcon className={cn(GLYPH, className)} aria-hidden="true" />;
    case 'ollama':
      return <OllamaGlyph className={className} />;
    case 'openrouter':
      return <OpenRouterGlyph className={className} />;
    case 'custom-openai':
      return <ServerIcon className={cn(GLYPH, className)} aria-hidden="true" />;
    default:
      return <SparklesIcon className={cn(GLYPH, className)} aria-hidden="true" />;
  }
}

/**
 * Icon for a transcription (STT) provider, keyed by provider id. Whisper and
 * Parakeet are on-device engines with no clean brand mark, so they get semantic
 * Heroicons; Apple uses its official mark. Replaces the emoji labels the model
 * dropdowns previously carried.
 */
export function TranscriptionProviderGlyph({
  provider,
  className,
}: {
  provider: string;
  className?: string;
}) {
  switch (provider) {
    case 'parakeet':
      return <BoltIcon className={cn(GLYPH, className)} aria-hidden="true" />;
    case 'apple':
      return <AppleGlyph className={className} />;
    case 'whisper':
    default:
      return <CpuChipIcon className={cn(GLYPH, className)} aria-hidden="true" />;
  }
}

/** Icon for a local model, keyed by family inferred from its name/id. */
export function ModelGlyph({
  model,
  className,
}: {
  model: string;
  className?: string;
}) {
  const id = (model || '').toLowerCase();
  if (id.includes('gemma')) return <GemmaGlyph className={className} />;
  if (id.includes('qwen')) return <QwenGlyph className={className} />;
  if (id.includes('llama')) return <OllamaGlyph className={className} />;
  return <CpuChipIcon className={cn(GLYPH, className)} aria-hidden="true" />;
}
